-- Migration 0059: exercise-science evidence layer — remaining 13 muscles (pass 3).
--
-- Completes the curated+cited rollout: chest, triceps, front_delts, lats,
-- mid_back, rear_delts, side_delts, traps, forearms, quads, hamstrings, calves,
-- abs, adductors, lower_back. Same standard as 0057/0058 — every row carries a
-- real citation (Consensus literature). Catalog gaps flagged in the briefs:
-- forearms (no wrist flexion/extension movements) and adductors (no isolation)
-- are trained only via cross-mapped compounds until movements are added.

-- The same movement develops several muscles (a squat builds quads, glutes, and
-- adductors), so exercise_science is keyed by (exercise_name, muscle), not
-- exercise_name alone. Recreate with the composite key, preserving 0057/0058.
CREATE TABLE exercise_science_v2 (
    exercise_name TEXT NOT NULL,
    muscle        TEXT NOT NULL,
    region        TEXT,
    length_bias   TEXT NOT NULL,
    rep_low       INTEGER NOT NULL,
    rep_high      INTEGER NOT NULL,
    sfr_tier      TEXT NOT NULL DEFAULT 'moderate',
    rationale     TEXT NOT NULL,
    citation      TEXT NOT NULL,
    citation_url  TEXT,
    PRIMARY KEY (exercise_name, muscle)
);
    rep_low, rep_high, sfr_tier, rationale, citation, citation_url FROM exercise_science;
DROP TABLE exercise_science;
ALTER TABLE exercise_science_v2 RENAME TO exercise_science;

